import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import type { Order } from '../../src/models/order.js';
import type { User } from '../../src/models/user.js';

function makeOrder(overrides: Partial<Order> & { id: string }): Order {
  return {
    userId: 'user-1',
    items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
    total: 10,
    status: 'delivered',
    createdAt: new Date('2025-01-15'),
    updatedAt: new Date('2025-01-15'),
    ...overrides,
  };
}

function makeUser(overrides: Partial<User> & { id: string }): User {
  return {
    name: 'Test User',
    email: 'test@example.com',
    role: 'member',
    createdAt: new Date('2025-01-01'),
    updatedAt: new Date('2025-01-01'),
    ...overrides,
  };
}

describe('AnalyticsService', () => {
  let db: Database;
  let orderRepo: OrderRepository;
  let userRepo: UserRepository;
  let service: AnalyticsService;

  beforeEach(() => {
    db = new Database();
    orderRepo = new OrderRepository(db);
    userRepo = new UserRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
  });

  // ─── getOrderMetrics ─────────────────────────────────────────────────

  describe('getOrderMetrics', () => {
    it('should return zero metrics when there are no orders', () => {
      const result = service.getOrderMetrics();
      expect(result.totalOrders).toBe(0);
      expect(result.totalRevenue).toBe(0);
      expect(result.averageOrderValue).toBe(0);
      expect(result.ordersByStatus.pending).toBe(0);
      expect(result.ordersByStatus.delivered).toBe(0);
    });

    it('should compute metrics for all orders when no date range given', () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 100, status: 'pending' }));
      orderRepo.save(makeOrder({ id: 'o2', total: 200, status: 'delivered' }));
      orderRepo.save(makeOrder({ id: 'o3', total: 300, status: 'pending' }));

      const result = service.getOrderMetrics();
      expect(result.totalOrders).toBe(3);
      expect(result.totalRevenue).toBe(600);
      expect(result.averageOrderValue).toBe(200);
      expect(result.ordersByStatus.pending).toBe(2);
      expect(result.ordersByStatus.delivered).toBe(1);
    });

    it('should filter orders by date range', () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 50, createdAt: new Date('2025-01-01') }));
      orderRepo.save(makeOrder({ id: 'o2', total: 100, createdAt: new Date('2025-02-15') }));
      orderRepo.save(makeOrder({ id: 'o3', total: 200, createdAt: new Date('2025-03-30') }));

      const result = service.getOrderMetrics(
        new Date('2025-02-01'),
        new Date('2025-02-28'),
      );
      expect(result.totalOrders).toBe(1);
      expect(result.totalRevenue).toBe(100);
    });

    it('should filter with only startDate', () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 50, createdAt: new Date('2025-01-01') }));
      orderRepo.save(makeOrder({ id: 'o2', total: 100, createdAt: new Date('2025-06-01') }));

      const result = service.getOrderMetrics(new Date('2025-03-01'));
      expect(result.totalOrders).toBe(1);
      expect(result.totalRevenue).toBe(100);
    });

    it('should filter with only endDate', () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 50, createdAt: new Date('2025-01-01') }));
      orderRepo.save(makeOrder({ id: 'o2', total: 100, createdAt: new Date('2025-06-01') }));

      const result = service.getOrderMetrics(undefined, new Date('2025-03-01'));
      expect(result.totalOrders).toBe(1);
      expect(result.totalRevenue).toBe(50);
    });

    it('should count all order statuses', () => {
      orderRepo.save(makeOrder({ id: 'o1', status: 'pending' }));
      orderRepo.save(makeOrder({ id: 'o2', status: 'confirmed' }));
      orderRepo.save(makeOrder({ id: 'o3', status: 'shipped' }));
      orderRepo.save(makeOrder({ id: 'o4', status: 'delivered' }));
      orderRepo.save(makeOrder({ id: 'o5', status: 'cancelled' }));

      const result = service.getOrderMetrics();
      expect(result.ordersByStatus.pending).toBe(1);
      expect(result.ordersByStatus.confirmed).toBe(1);
      expect(result.ordersByStatus.shipped).toBe(1);
      expect(result.ordersByStatus.delivered).toBe(1);
      expect(result.ordersByStatus.cancelled).toBe(1);
    });

    it('should handle single order', () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 42 }));
      const result = service.getOrderMetrics();
      expect(result.totalOrders).toBe(1);
      expect(result.averageOrderValue).toBe(42);
    });
  });

  // ─── getUserMetrics ───────────────────────────────────────────────────

  describe('getUserMetrics', () => {
    it('should return zero metrics when there are no users', () => {
      const result = service.getUserMetrics();
      expect(result.totalUsers).toBe(0);
      expect(result.newUsersInPeriod).toBe(0);
      expect(result.usersByRole).toEqual({});
    });

    it('should compute total users and role breakdown', () => {
      userRepo.save(makeUser({ id: 'u1', role: 'admin' }));
      userRepo.save(makeUser({ id: 'u2', role: 'member' }));
      userRepo.save(makeUser({ id: 'u3', role: 'member' }));
      userRepo.save(makeUser({ id: 'u4', role: 'viewer' }));

      const result = service.getUserMetrics();
      expect(result.totalUsers).toBe(4);
      expect(result.usersByRole).toEqual({ admin: 1, member: 2, viewer: 1 });
      expect(result.newUsersInPeriod).toBe(0);
    });

    it('should count new users in a period', () => {
      userRepo.save(makeUser({ id: 'u1', createdAt: new Date('2025-01-05') }));
      userRepo.save(makeUser({ id: 'u2', createdAt: new Date('2025-02-15') }));
      userRepo.save(makeUser({ id: 'u3', createdAt: new Date('2025-03-20') }));

      const result = service.getUserMetrics(
        new Date('2025-02-01'),
        new Date('2025-02-28'),
      );
      expect(result.totalUsers).toBe(3);
      expect(result.newUsersInPeriod).toBe(1);
    });

    it('should count new users with only periodStart', () => {
      userRepo.save(makeUser({ id: 'u1', createdAt: new Date('2025-01-05') }));
      userRepo.save(makeUser({ id: 'u2', createdAt: new Date('2025-06-15') }));

      const result = service.getUserMetrics(new Date('2025-03-01'));
      expect(result.totalUsers).toBe(2);
      expect(result.newUsersInPeriod).toBe(1);
    });

    it('should count new users with only periodEnd', () => {
      userRepo.save(makeUser({ id: 'u1', createdAt: new Date('2025-01-05') }));
      userRepo.save(makeUser({ id: 'u2', createdAt: new Date('2025-06-15') }));

      const result = service.getUserMetrics(undefined, new Date('2025-03-01'));
      expect(result.totalUsers).toBe(2);
      expect(result.newUsersInPeriod).toBe(1);
    });
  });

  // ─── getTopProducts ───────────────────────────────────────────────────

  describe('getTopProducts', () => {
    it('should return empty array when there are no orders', () => {
      const result = service.getTopProducts();
      expect(result).toEqual([]);
    });

    it('should aggregate product revenue across orders', () => {
      orderRepo.save(makeOrder({
        id: 'o1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 50 },
        ],
        total: 70,
      }));
      orderRepo.save(makeOrder({
        id: 'o2',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 3, unitPrice: 10 },
        ],
        total: 30,
      }));

      const result = service.getTopProducts();
      expect(result).toHaveLength(2);
      // p1: 5 qty * $10 = $50, p2: 1 qty * $50 = $50
      expect(result[0].productId).toBe('p1');
      expect(result[0].totalQuantity).toBe(5);
      expect(result[0].totalRevenue).toBe(50);
      expect(result[1].productId).toBe('p2');
      expect(result[1].totalRevenue).toBe(50);
    });

    it('should exclude cancelled orders', () => {
      orderRepo.save(makeOrder({
        id: 'o1',
        status: 'delivered',
        items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
        total: 20,
      }));
      orderRepo.save(makeOrder({
        id: 'o2',
        status: 'cancelled',
        items: [{ productId: 'p1', name: 'Widget', quantity: 100, unitPrice: 10 }],
        total: 1000,
      }));

      const result = service.getTopProducts();
      expect(result).toHaveLength(1);
      expect(result[0].totalQuantity).toBe(2);
    });

    it('should respect the limit parameter', () => {
      for (let i = 0; i < 5; i++) {
        orderRepo.save(makeOrder({
          id: `o${i}`,
          items: [{ productId: `p${i}`, name: `Product ${i}`, quantity: 1, unitPrice: (i + 1) * 10 }],
          total: (i + 1) * 10,
        }));
      }

      const result = service.getTopProducts(undefined, undefined, 3);
      expect(result).toHaveLength(3);
      // Should be sorted by revenue descending
      expect(result[0].totalRevenue).toBe(50);
      expect(result[1].totalRevenue).toBe(40);
      expect(result[2].totalRevenue).toBe(30);
    });

    it('should filter by date range', () => {
      orderRepo.save(makeOrder({
        id: 'o1',
        createdAt: new Date('2025-01-15'),
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 100 }],
        total: 100,
      }));
      orderRepo.save(makeOrder({
        id: 'o2',
        createdAt: new Date('2025-03-15'),
        items: [{ productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 200 }],
        total: 200,
      }));

      const result = service.getTopProducts(
        new Date('2025-03-01'),
        new Date('2025-03-31'),
      );
      expect(result).toHaveLength(1);
      expect(result[0].productId).toBe('p2');
    });

    it('should sort products by revenue descending', () => {
      orderRepo.save(makeOrder({
        id: 'o1',
        items: [
          { productId: 'p1', name: 'Cheap', quantity: 1, unitPrice: 5 },
          { productId: 'p2', name: 'Expensive', quantity: 1, unitPrice: 500 },
          { productId: 'p3', name: 'Mid', quantity: 1, unitPrice: 50 },
        ],
        total: 555,
      }));

      const result = service.getTopProducts();
      expect(result[0].productId).toBe('p2');
      expect(result[1].productId).toBe('p3');
      expect(result[2].productId).toBe('p1');
    });
  });

  // ─── getTimeSeries ────────────────────────────────────────────────────

  describe('getTimeSeries', () => {
    it('should return empty buckets when there are no orders', () => {
      const result = service.getTimeSeries(
        'revenue',
        new Date('2025-01-01'),
        new Date('2025-01-03'),
        'day',
      );
      expect(result.metric).toBe('revenue');
      expect(result.startDate).toBe('2025-01-01');
      expect(result.endDate).toBe('2025-01-03');
      expect(result.dataPoints).toHaveLength(3);
      expect(result.dataPoints.every((dp) => dp.value === 0)).toBe(true);
    });

    it('should aggregate revenue by day', () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 100, createdAt: new Date('2025-01-01') }));
      orderRepo.save(makeOrder({ id: 'o2', total: 200, createdAt: new Date('2025-01-01') }));
      orderRepo.save(makeOrder({ id: 'o3', total: 50, createdAt: new Date('2025-01-02') }));

      const result = service.getTimeSeries(
        'revenue',
        new Date('2025-01-01'),
        new Date('2025-01-03'),
        'day',
      );

      expect(result.dataPoints).toHaveLength(3);
      const jan1 = result.dataPoints.find((dp) => dp.date === '2025-01-01');
      const jan2 = result.dataPoints.find((dp) => dp.date === '2025-01-02');
      const jan3 = result.dataPoints.find((dp) => dp.date === '2025-01-03');
      expect(jan1?.value).toBe(300);
      expect(jan2?.value).toBe(50);
      expect(jan3?.value).toBe(0);
    });

    it('should aggregate order count by day', () => {
      orderRepo.save(makeOrder({ id: 'o1', createdAt: new Date('2025-01-01') }));
      orderRepo.save(makeOrder({ id: 'o2', createdAt: new Date('2025-01-01') }));
      orderRepo.save(makeOrder({ id: 'o3', createdAt: new Date('2025-01-02') }));

      const result = service.getTimeSeries(
        'orderCount',
        new Date('2025-01-01'),
        new Date('2025-01-02'),
        'day',
      );

      expect(result.dataPoints).toHaveLength(2);
      const jan1 = result.dataPoints.find((dp) => dp.date === '2025-01-01');
      const jan2 = result.dataPoints.find((dp) => dp.date === '2025-01-02');
      expect(jan1?.value).toBe(2);
      expect(jan2?.value).toBe(1);
    });

    it('should exclude orders outside the date range', () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 100, createdAt: new Date('2024-12-31') }));
      orderRepo.save(makeOrder({ id: 'o2', total: 200, createdAt: new Date('2025-01-01') }));
      orderRepo.save(makeOrder({ id: 'o3', total: 300, createdAt: new Date('2025-01-04') }));

      const result = service.getTimeSeries(
        'revenue',
        new Date('2025-01-01'),
        new Date('2025-01-03'),
        'day',
      );

      const total = result.dataPoints.reduce((sum, dp) => sum + dp.value, 0);
      expect(total).toBe(200);
    });

    it('should aggregate by month', () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 100, createdAt: new Date('2025-01-15') }));
      orderRepo.save(makeOrder({ id: 'o2', total: 200, createdAt: new Date('2025-02-10') }));
      orderRepo.save(makeOrder({ id: 'o3', total: 50, createdAt: new Date('2025-01-20') }));

      const result = service.getTimeSeries(
        'revenue',
        new Date('2025-01-01'),
        new Date('2025-03-01'),
        'month',
      );

      expect(result.dataPoints.length).toBeGreaterThanOrEqual(3);
      const jan = result.dataPoints.find((dp) => dp.date === '2025-01-01');
      const feb = result.dataPoints.find((dp) => dp.date === '2025-02-01');
      expect(jan?.value).toBe(150);
      expect(feb?.value).toBe(200);
    });

    it('should aggregate by week', () => {
      // 2025-01-06 is a Monday
      orderRepo.save(makeOrder({ id: 'o1', total: 100, createdAt: new Date('2025-01-06') }));
      orderRepo.save(makeOrder({ id: 'o2', total: 200, createdAt: new Date('2025-01-08') }));
      // Next week
      orderRepo.save(makeOrder({ id: 'o3', total: 50, createdAt: new Date('2025-01-13') }));

      const result = service.getTimeSeries(
        'revenue',
        new Date('2025-01-06'),
        new Date('2025-01-19'),
        'week',
      );

      expect(result.dataPoints.length).toBeGreaterThanOrEqual(2);
      const week1 = result.dataPoints.find((dp) => dp.date === '2025-01-06');
      const week2 = result.dataPoints.find((dp) => dp.date === '2025-01-13');
      expect(week1?.value).toBe(300);
      expect(week2?.value).toBe(50);
    });

    it('should handle single-day range', () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 42, createdAt: new Date('2025-01-01') }));

      const result = service.getTimeSeries(
        'revenue',
        new Date('2025-01-01'),
        new Date('2025-01-01'),
        'day',
      );

      expect(result.dataPoints).toHaveLength(1);
      expect(result.dataPoints[0].value).toBe(42);
    });

    it('should default granularity to day', () => {
      const result = service.getTimeSeries(
        'revenue',
        new Date('2025-01-01'),
        new Date('2025-01-03'),
      );

      expect(result.dataPoints).toHaveLength(3);
      expect(result.dataPoints[0].date).toBe('2025-01-01');
    });
  });

  // ─── getDashboardData ─────────────────────────────────────────────────

  describe('getDashboardData', () => {
    it('should compose all analytics into dashboard data', () => {
      userRepo.save(makeUser({ id: 'u1', role: 'admin', createdAt: new Date('2025-01-05') }));
      userRepo.save(makeUser({ id: 'u2', role: 'member', createdAt: new Date('2025-01-15') }));

      orderRepo.save(makeOrder({
        id: 'o1',
        total: 100,
        status: 'delivered',
        createdAt: new Date('2025-01-10'),
        items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 50 }],
      }));
      orderRepo.save(makeOrder({
        id: 'o2',
        total: 200,
        status: 'pending',
        createdAt: new Date('2025-01-20'),
        items: [{ productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 200 }],
      }));

      const start = new Date('2025-01-01');
      const end = new Date('2025-01-31');
      const result = service.getDashboardData(start, end);

      expect(result.periodStart).toEqual(start);
      expect(result.periodEnd).toEqual(end);
      expect(result.generatedAt).toBeInstanceOf(Date);

      // Order metrics
      expect(result.orderMetrics.totalOrders).toBe(2);
      expect(result.orderMetrics.totalRevenue).toBe(300);

      // User metrics
      expect(result.userMetrics.totalUsers).toBe(2);
      expect(result.userMetrics.newUsersInPeriod).toBe(2);

      // Time series
      expect(result.revenueTimeSeries.metric).toBe('revenue');
      expect(result.ordersTimeSeries.metric).toBe('orderCount');
      expect(result.revenueTimeSeries.dataPoints.length).toBeGreaterThan(0);

      // Top products
      expect(result.topProducts).toHaveLength(2);
    });

    it('should return empty dashboard data when no data exists', () => {
      const start = new Date('2025-01-01');
      const end = new Date('2025-01-31');
      const result = service.getDashboardData(start, end);

      expect(result.orderMetrics.totalOrders).toBe(0);
      expect(result.userMetrics.totalUsers).toBe(0);
      expect(result.topProducts).toHaveLength(0);
      expect(result.revenueTimeSeries.dataPoints.every((dp) => dp.value === 0)).toBe(true);
    });
  });
});

