private getBucketKey(date: Date, granularity: TimeGranularity): string {
  const year = date.getUTCFullYear();
  const month = String(date.getUTCMonth() + 1).padStart(2, '0');
  const day = String(date.getUTCDate()).padStart(2, '0');

  switch (granularity) {
    case 'day':
      return `${year}-${month}-${day}`;
    case 'week': {
      // Use the Monday of the week as the bucket key
      const d = new Date(date);
      const dayOfWeek = d.getUTCDay();
      const diff = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
      d.setUTCDate(d.getUTCDate() + diff);
      const wy = d.getUTCFullYear();
      const wm = String(d.getUTCMonth() + 1).padStart(2, '0');
      const wd = String(d.getUTCDate()).padStart(2, '0');
      return `${wy}-${wm}-${wd}`;
    }
    case 'month':
      return `${year}-${month}-01`;
  }
}

